+
+type DaemonService = {
+  label: string
+  loadedText: string
+  notLoadedText: string
+  install: (args: DaemonServiceInstallArgs) => Promise<void>
+  uninstall: (args: {
+    env: Record<string, string | undefined>
+    stdout: NodeJS.WritableStream
+  }) => Promise<void>
