+function resolveDaemonService(): DaemonService {
+  if (process.platform === 'darwin') {
+    return {
+      label: 'LaunchAgent',
+      loadedText: 'loaded',
+      notLoadedText: 'not loaded',
+      install: async (args) => {
+        await installLaunchAgent(args)
